/**
 * Storefront Autonomy Cockpit — shared types and Zod schemas.
 *
 * No fs imports. Safe to use from client components, server components,
 * and route handlers. All types are inferred from their Zod schemas so
 * the schema IS the single source of truth.
 *
 * Shapes are derived from real heal-log.jsonl observations (2026-05-30):
 *   - Line 1: full DRY cycle with s1/s2/s3/s4 detail; cycle=1 (number)
 *   - Lines 2-3: abbreviated scheduled cycles; cycle="scheduled" (string)
 *     carrying trigger, note, liveVer fields not present in line 1.
 * z.passthrough() is used on HealCycleEntry so extra fields survive
 * round-trips without being stripped.
 */
import { z } from 'zod';

// ---------------------------------------------------------------------------
// Primitive enums
// ---------------------------------------------------------------------------

export const CycleVerdictSchema = z.enum([
  'healthy',
  'HEALTHY',
  'regressions',
  'REGRESSIONS',
  'escalated',
  'ESCALATED',
]);
export type CycleVerdict = z.infer<typeof CycleVerdictSchema>;

export const SignalStatusSchema = z.enum(['PASS', 'FAIL', 'UNAVAILABLE', 'skipped']);
export type SignalStatus = z.infer<typeof SignalStatusSchema>;

// ---------------------------------------------------------------------------
// S1 — HTTP health grid
// Observed: pages keyed by label ("Homepage", "Shop", ...) not path
// ---------------------------------------------------------------------------

export const S1PageDetailSchema = z.object({
  http: z.number().int(),
  kb: z.number(),
  floor: z.number(),
  phpErr: z.number().int(),
});
export type S1PageDetail = z.infer<typeof S1PageDetailSchema>;

export const S1DetailSchema = z.object({
  status: SignalStatusSchema,
  pages: z.record(z.string(), S1PageDetailSchema),
});
export type S1Detail = z.infer<typeof S1DetailSchema>;

// ---------------------------------------------------------------------------
// S2 — Canon-drift checklist
// Observed: checks keyed by check-id, value is presence string e.g. "present(4)"
// ---------------------------------------------------------------------------

export const S2DetailSchema = z.object({
  status: SignalStatusSchema,
  checks: z.record(z.string(), z.string()),
});
export type S2Detail = z.infer<typeof S2DetailSchema>;

// ---------------------------------------------------------------------------
// S3 — Asset version card
// ---------------------------------------------------------------------------

export const S3DetailSchema = z.object({
  status: SignalStatusSchema,
  assetVersion: z.string(),
  refs: z.number().int().optional(),
  minCssMain: z.number().int().optional(),
  minCssDesignTokens: z.number().int().optional(),
  minJsPremiumInteractions: z.number().int().optional(),
});
export type S3Detail = z.infer<typeof S3DetailSchema>;

// ---------------------------------------------------------------------------
// S4 — Advisory (Lighthouse / advanced signals)
// Observed: { status, note, available } — S4 is UNAVAILABLE on first cycle
// ---------------------------------------------------------------------------

export const S4DetailSchema = z
  .object({
    status: SignalStatusSchema,
    note: z.string().optional(),
    available: z.boolean().optional(),
  })
  .passthrough();
export type S4Detail = z.infer<typeof S4DetailSchema>;

// ---------------------------------------------------------------------------
// HealCycleEntry — one line from heal-log.jsonl
// cycle: z.union([z.number(), z.string()]) — observed as both numeric and "scheduled"
// passthrough() so trigger/liveVer/note from abbreviated lines survive
// ---------------------------------------------------------------------------

export const HealCycleEntrySchema = z
  .object({
    ts: z.string(),
    cycle: z.union([z.number(), z.string()]),
    signalsChecked: z.array(z.string()).default([]),
    regressions: z.array(z.string()).default([]),
    healed: z.array(z.string()).default([]),
    gate: z.string().optional(),
    deployed: z.boolean().default(false),
    verdict: z.string(),
    dryManifest: z.unknown().nullable().optional(),
    lessons: z.array(z.string()).optional(),
    improvements: z.array(z.string()).optional(),
    note: z.string().optional(),
    s1: S1DetailSchema.optional(),
    s2: S2DetailSchema.optional(),
    s3: S3DetailSchema.optional(),
    s4: S4DetailSchema.optional(),
  })
  .passthrough();
export type HealCycleEntry = z.infer<typeof HealCycleEntrySchema>;

// ---------------------------------------------------------------------------
// Knowledge base
// ---------------------------------------------------------------------------

export const KnowledgeSignatureSchema = z.object({
  signature: z.string(),
  surface: z.string(),
  rootCause: z.string(),
  fixPattern: z.string(),
  recurrences: z.number().int(),
  firstSeen: z.string(),
  lastSeen: z.string(),
  lastOutcome: z.enum(['healed', 'escalated', 'dry']),
  preventionAdded: z.string().nullable(),
});
export type KnowledgeSignature = z.infer<typeof KnowledgeSignatureSchema>;

export const RecurrenceTrendSchema = z.object({
  cycle: z.number().int(),
  meanRecurrences: z.number(),
  signaturesActive: z.number().int(),
});
export type RecurrenceTrend = z.infer<typeof RecurrenceTrendSchema>;

export const HealKnowledgeSchema = z.object({
  version: z.number().int(),
  cycles: z.number().int(),
  note: z.string().optional(),
  signatures: z.array(KnowledgeSignatureSchema),
  preventions: z.array(z.string()),
  metric_recurrence_trend: z.array(RecurrenceTrendSchema),
});
export type HealKnowledge = z.infer<typeof HealKnowledgeSchema>;

// ---------------------------------------------------------------------------
// Theme-health baseline — mirrors theme-health-baseline.json exactly
// ---------------------------------------------------------------------------

export const BaselinePageSchema = z.object({
  path: z.string(),
  expectedHttp: z.number().int(),
  observedKB: z.number(),
  sizeFloorKB: z.number(),
  phpError: z.boolean(),
  label: z.string(),
});
export type BaselinePage = z.infer<typeof BaselinePageSchema>;

export const BaselineCanonCheckSchema = z.object({
  id: z.string(),
  surface: z.string(),
  path: z.string(),
  grep: z.string(),
  expectedPresent: z.boolean(),
  observedPresent: z.boolean(),
  severity: z.string(),
  description: z.string(),
});
export type BaselineCanonCheck = z.infer<typeof BaselineCanonCheckSchema>;

export const BaselineAssetCheckSchema = z
  .object({
    id: z.string(),
    description: z.string().optional(),
    expectedVersion: z.string().optional(),
    observedVersion: z.string().optional(),
    matchesSource: z.boolean().optional(),
    url: z.string().optional(),
    expectedHttp: z.number().int().optional(),
    observedHttp: z.number().int().optional(),
  })
  .passthrough();
export type BaselineAssetCheck = z.infer<typeof BaselineAssetCheckSchema>;

export const ThemeHealthBaselineSchema = z.object({
  version: z.number().int(),
  assetVersion: z.string(),
  capturedAt: z.string(),
  note: z.string().optional(),
  pages: z.array(BaselinePageSchema),
  canonChecks: z.array(BaselineCanonCheckSchema),
  assetChecks: z.array(BaselineAssetCheckSchema),
});
export type ThemeHealthBaseline = z.infer<typeof ThemeHealthBaselineSchema>;

// ---------------------------------------------------------------------------
// Consolidated cockpit payload — what the API route returns
// ---------------------------------------------------------------------------

export const AutonomyCockpitDataSchema = z.object({
  /** Most-recent line from heal-log.jsonl regardless of detail level */
  latestCycle: HealCycleEntrySchema.nullable(),
  /** Most-recent line that contains s1/s2/s3 detail keys */
  latestWithDetail: HealCycleEntrySchema.nullable(),
  /** All parsed cycle entries, chronological */
  allCycles: z.array(HealCycleEntrySchema),
  /** Full heal-knowledge.json payload */
  knowledge: HealKnowledgeSchema,
  /** theme-health-baseline.json */
  baseline: ThemeHealthBaselineSchema,
  /** true when fs adapter is in use (local host), false when mock (Vercel) */
  isLive: z.boolean(),
});
export type AutonomyCockpitData = z.infer<typeof AutonomyCockpitDataSchema>;

// ---------------------------------------------------------------------------
// Hexagonal port — both adapters must satisfy this interface
// ---------------------------------------------------------------------------

export interface AutonomyAdapter {
  cockpit(): Promise<AutonomyCockpitData>;
}

// ---------------------------------------------------------------------------
// Utility: normalizeVerdict
// Converts mixed-case verdict strings to lowercase canonical form.
// e.g. "HEALTHY" → "healthy", "REGRESSIONS" → "regressions"
// ---------------------------------------------------------------------------

export type NormalizedVerdict = 'healthy' | 'regressions' | 'escalated';

export function normalizeVerdict(raw: string): NormalizedVerdict {
  const lower = raw.toLowerCase();
  if (lower === 'healthy') return 'healthy';
  if (lower === 'regressions') return 'regressions';
  return 'escalated';
}
