/**
 * Server-only fs adapter. Reads heal-log.jsonl, heal-knowledge.json,
 * and theme-health-baseline.json from the repo root (one level above
 * frontend/ since process.cwd() is frontend/ at build time).
 *
 * Falls back to mock-adapter output when files are missing (ENOENT)
 * rather than throwing — so Vercel builds stay green.
 */
import 'server-only';

import fs from 'fs';
import path from 'path';
import { HealCycleEntrySchema, HealKnowledgeSchema, ThemeHealthBaselineSchema } from './types';
import type { AutonomyCockpitData, HealCycleEntry } from './types';
import { mockAdapter } from './mock';

function repoRoot(): string {
  // process.cwd() = frontend/ when running `next dev` / `next build`
  // Go one level up to reach the repo root where .claude/ and tasks/ live.
  return path.join(process.cwd(), '..');
}

function readJsonFile<T>(filePath: string): T | null {
  try {
    const raw = fs.readFileSync(filePath, 'utf8');
    return JSON.parse(raw) as T;
  } catch {
    return null;
  }
}

function parseHealLog(filePath: string): HealCycleEntry[] {
  try {
    const raw = fs.readFileSync(filePath, 'utf8');
    const lines = raw.split('\n').filter((l) => l.trim().length > 0);
    const entries: HealCycleEntry[] = [];
    for (const line of lines) {
      try {
        const parsed = JSON.parse(line) as unknown;
        const result = HealCycleEntrySchema.safeParse(parsed);
        if (result.success) {
          entries.push(result.data);
        }
      } catch {
        // skip malformed lines silently
      }
    }
    return entries;
  } catch {
    return [];
  }
}

function hasSignalDetail(entry: HealCycleEntry): boolean {
  return entry.s1 !== undefined || entry.s2 !== undefined || entry.s3 !== undefined;
}

export const fsAdapter = {
  async cockpit(): Promise<AutonomyCockpitData> {
    const root = repoRoot();

    const knowledgeRaw = readJsonFile<unknown>(path.join(root, '.claude/state/heal-knowledge.json'));
    const baselineRaw = readJsonFile<unknown>(path.join(root, '.claude/state/theme-health-baseline.json'));
    const allCyclesAsc = parseHealLog(path.join(root, 'tasks/heal-log.jsonl'));

    // If essential files are missing, fall back to mock
    if (!knowledgeRaw || !baselineRaw) {
      return mockAdapter.cockpit();
    }

    const knowledgeResult = HealKnowledgeSchema.safeParse(knowledgeRaw);
    const baselineResult = ThemeHealthBaselineSchema.safeParse(baselineRaw);

    if (!knowledgeResult.success || !baselineResult.success) {
      return mockAdapter.cockpit();
    }

    // Reverse-chron for UI (newest first)
    const allCycles = [...allCyclesAsc].reverse();
    const latestCycle = allCycles[0] ?? null;
    const latestWithDetail = allCycles.find(hasSignalDetail) ?? null;

    return {
      latestCycle,
      latestWithDetail,
      allCycles,
      knowledge: knowledgeResult.data,
      baseline: baselineResult.data,
      isLive: true,
    };
  },
};
